Create the following 4 page files for the CitedBy Public project at C:\Users\User\citedby-public\pages\. These are gold-themed management pages and the new Marketplace page.

Use `cat > "filepath" << 'ENDOFFILE'` to write each file. Use single quotes around ENDOFFILE to prevent variable expansion.

First ensure the directory exists:
```bash
mkdir -p "C:/Users/User/citedby-public/pages"
```

## FILE 1: C:\Users\User\citedby-public\pages\Recharge.tsx

Gold-themed GTO Gas recharge page with 3 packs and Stripe checkout. No jsPDF.

```tsx
import React, { useState, useEffect } from 'react';
import { User } from '../types';
import { Fuel, Check, Loader2, Droplet, Database, ArrowLeft, ShieldCheck, CheckCircle2, LayoutDashboard, RefreshCcw } from 'lucide-react';
import StripeCheckout from '../components/StripeCheckout';

interface Props {
  onBack: () => void;
  onRecharge: (amount: number, planLevel: 'free' | 'pro' | 'enterprise') => void;
  user: User | null;
  onNavigate?: (view: string) => void;
  initialPackId?: number | null;
}

const Recharge: React.FC<Props> = ({ onBack, onRecharge, user, onNavigate, initialPackId }) => {
  const [viewMode, setViewMode] = useState<'list' | 'checkout' | 'result'>('list');
  const [paymentStatus, setPaymentStatus] = useState<'idle' | 'success' | 'error'>('idle');
  const [selectedPack, setSelectedPack] = useState<typeof packs[0] | null>(null);
  const [isProcessing, setIsProcessing] = useState(false);

  const packs = [
    { id: 1, name: "Le Jerrican", amount: 50, price: 15, icon: <Droplet size={32} />, popular: false, level: 'free' as const, features: ["Ideal pour un audit ponctuel", "Valable 1 an"] },
    { id: 2, name: "La Pompe", amount: 200, price: 49, icon: <Fuel size={32} />, popular: true, level: 'pro' as const, features: ["Pour les optimisations regulieres", "Support prioritaire", "+10% Bonus offert"] },
    { id: 3, name: "La Citerne", amount: 1000, price: 199, icon: <Database size={32} />, popular: false, level: 'enterprise' as const, features: ["Usage intensif / Agence", "Acces API Beta", "+20% Bonus offert"] },
  ];

  useEffect(() => {
    if (initialPackId) {
      const targetPack = packs.find(p => p.id === initialPackId);
      if (targetPack) { setSelectedPack(targetPack); setViewMode('checkout'); }
    }
  }, [initialPackId]);

  const handleSelectPack = (pack: typeof packs[0]) => {
    setSelectedPack(pack);
    setViewMode('checkout');
  };

  const handlePaymentComplete = () => {
    if (!selectedPack) return;
    setIsProcessing(true);
    setTimeout(() => {
      onRecharge(selectedPack.amount, selectedPack.level);
      setPaymentStatus('success');
      setViewMode('result');
      setIsProcessing(false);
    }, 2000);
  };

  // Success view
  if (viewMode === 'result' && paymentStatus === 'success') {
    return (
      <div className="w-full px-6 py-8 flex flex-col items-center justify-center min-h-[60vh] animate-in fade-in zoom-in duration-500">
        <div className="w-20 h-20 rounded-full bg-emerald-500/20 flex items-center justify-center mb-6"><CheckCircle2 size={40} className="text-emerald-400" /></div>
        <h2 className="text-2xl font-bold text-white mb-2">Recharge reussie !</h2>
        <p className="text-gray-400 mb-2">{selectedPack?.amount} GTO Gas ajoutes a votre compte</p>
        <p className="text-gray-500 text-sm mb-8">Nouveau solde : {(user?.credits || 0)} Gas</p>
        <div className="flex gap-4">
          <button onClick={() => onNavigate?.('dashboard')} className="btn-gradient px-6 py-3 flex items-center gap-2"><LayoutDashboard size={18} /> Dashboard</button>
          <button onClick={() => { setViewMode('list'); setPaymentStatus('idle'); }} className="px-6 py-3 rounded-full border border-white/[0.08] bg-white/[0.04] hover:bg-white/[0.08] text-gray-300 flex items-center gap-2"><RefreshCcw size={18} /> Autre recharge</button>
        </div>
      </div>
    );
  }

  // Checkout view
  if (viewMode === 'checkout' && selectedPack) {
    return (
      <div className="w-full px-6 py-8 max-w-2xl mx-auto">
        <button onClick={() => setViewMode('list')} className="flex items-center gap-2 text-gray-500 hover:text-white text-sm mb-6 transition-colors"><ArrowLeft size={16} /> Retour aux packs</button>
        <div className="ninja-card p-8">
          <div className="flex items-center justify-between mb-6 pb-6 border-b border-white/[0.06]">
            <div><h2 className="text-xl font-bold text-white">{selectedPack.name}</h2><p className="text-gray-500 text-sm">{selectedPack.amount} GTO Gas</p></div>
            <div className="text-3xl font-bold gradient-text">{selectedPack.price}€</div>
          </div>
          <StripeCheckout amount={selectedPack.price} onComplete={handlePaymentComplete} isProcessing={isProcessing} label={`Payer ${selectedPack.price}€ HT`} />
        </div>
      </div>
    );
  }

  // Pack list
  return (
    <div className="w-full px-6 py-8">
      <div className="mb-8">
        <h1 className="text-3xl font-bold text-white">Station <span className="gradient-text">GTO Gas</span></h1>
        <p className="text-gray-500 text-sm mt-1">Rechargez votre carburant algorithmique pour executer audits et analyses</p>
      </div>
      {user && (
        <div className="ninja-card p-5 mb-8 flex items-center gap-4">
          <Fuel size={24} className="text-amber-400" />
          <div><div className="text-white font-bold">{user.credits} GTO Gas</div><div className="text-xs text-gray-500">Solde actuel • Plan {user.plan}</div></div>
        </div>
      )}
      <div className="grid md:grid-cols-3 gap-6">
        {packs.map(pack => (
          <div key={pack.id} className={`relative ninja-card p-8 flex flex-col ${pack.popular ? '!border-amber-500/30 shadow-[0_0_50px_rgba(218,165,32,0.08)] md:scale-105 z-10' : ''}`}>
            {pack.popular && <div className="absolute -top-4 left-1/2 -translate-x-1/2 btn-gradient text-xs font-bold px-5 py-1.5 rounded-full uppercase tracking-wider shadow-lg">Le Choix Expert</div>}
            <div className="mb-6 flex items-center justify-between pt-2">
              <div className={`w-14 h-14 rounded-xl flex items-center justify-center ${pack.popular ? 'bg-gradient-to-br from-amber-400 to-amber-700 text-white' : 'bg-amber-500/10 text-gray-500'}`}>{pack.icon}</div>
              <div className="text-right"><span className="block text-3xl font-bold gradient-text">{pack.amount}</span><span className="text-[11px] text-gray-600 uppercase font-bold tracking-wider">Credits Gas</span></div>
            </div>
            <h3 className="text-xl font-bold text-white mb-2">{pack.name}</h3>
            <div className="flex items-baseline gap-1 mb-6"><span className="text-4xl font-bold text-white">{pack.price}€</span><span className="text-sm text-gray-600">HT</span></div>
            <ul className="space-y-3 mb-8 flex-1">{pack.features.map((f, i) => <li key={i} className="flex items-start gap-3 text-sm text-gray-400"><Check size={16} className={`mt-0.5 shrink-0 ${pack.popular ? 'text-amber-400' : 'text-gray-600'}`} />{f}</li>)}</ul>
            <button onClick={() => handleSelectPack(pack)} className={`w-full py-3.5 rounded-full font-bold flex items-center justify-center gap-2 transition-all ${pack.popular ? 'btn-gradient shadow-lg shadow-amber-900/20' : 'bg-white/[0.04] border border-white/[0.08] text-gray-300 hover:bg-white/[0.07]'}`}>Recharger</button>
          </div>
        ))}
      </div>
      <div className="flex justify-center items-center gap-6 mt-8 text-sm text-gray-500"><ShieldCheck size={16} className="text-amber-400" /><span>Paiement securise via Stripe</span><span>•</span><span>Facture PDF automatique</span></div>
    </div>
  );
};

export default Recharge;
```

## FILE 2: C:\Users\User\citedby-public\pages\Account.tsx

Simplified account page with 3 tabs (profile, subscription, billing). No whitelabel tab. No jsPDF. Gold theme.

```tsx
import React, { useState } from 'react';
import { User } from '../types';
import { User as UserIcon, Mail, Key, Bell, LogOut, Fuel, Check, Copy, Droplet, Database, CreditCard, ShieldCheck, History, Sparkles, Zap, ArrowUpRight } from 'lucide-react';
import StripeCheckout from '../components/StripeCheckout';

interface AccountProps {
  user: User | null;
  onLogout: () => void;
  onNavigate: (view: any) => void;
  onUpgrade: (plan: 'free' | 'pro' | 'enterprise') => void;
  initialTab?: 'profile' | 'subscription' | 'billing';
}

const Account: React.FC<AccountProps> = ({ user, onLogout, onNavigate, onUpgrade, initialTab = 'profile' }) => {
  const [activeTab, setActiveTab] = useState<'profile' | 'subscription' | 'billing'>(initialTab);
  const [apiKeyCopied, setApiKeyCopied] = useState(false);
  const [upgradeModal, setUpgradeModal] = useState<{ planId: string; planName: string; newPrice: number } | null>(null);
  const [paymentStep, setPaymentStep] = useState<'recap' | 'payment' | 'success'>('recap');
  const [isProcessing, setIsProcessing] = useState(false);
  const [paymentHistory] = useState([
    { id: 'INV-2024-003', date: '01/03/2024', amount: 89.00, desc: 'Abonnement Pro (Mensuel)', status: 'Paye' },
    { id: 'INV-2024-002', date: '01/02/2024', amount: 89.00, desc: 'Abonnement Pro (Mensuel)', status: 'Paye' },
    { id: 'INV-2024-001', date: '15/01/2024', amount: 49.00, desc: 'Pack GTO Gas (La Pompe)', status: 'Paye' },
  ]);

  const plans = [
    { id: 'starter', name: 'Starter', price: 29, features: ['1 projet', '50 Gas/mois', 'Audit AEO', 'Alertes email'], current: user?.plan === 'free' },
    { id: 'pro', name: 'Pro', price: 89, features: ['3 projets', '200 Gas/mois', 'Monitoring IA', 'Support prioritaire', 'Marketplace acces'], current: user?.plan === 'pro', popular: true },
    { id: 'agency', name: 'Agency', price: 299, features: ['Projets illimites', '1000 Gas/mois', 'API acces', 'Support dedie', 'Marketplace premium'], current: user?.plan === 'enterprise' },
  ];

  const handleCopyApiKey = () => {
    navigator.clipboard.writeText('cb_pub_live_' + (user?.id || 'demo').substring(0, 16));
    setApiKeyCopied(true);
    setTimeout(() => setApiKeyCopied(false), 2000);
  };

  const handleUpgradePayment = () => {
    if (!upgradeModal) return;
    setIsProcessing(true);
    setTimeout(() => {
      const planMap: Record<string, 'free' | 'pro' | 'enterprise'> = { starter: 'free', pro: 'pro', agency: 'enterprise' };
      onUpgrade(planMap[upgradeModal.planId] || 'free');
      setPaymentStep('success');
      setIsProcessing(false);
    }, 2000);
  };

  if (!user) return <div className="p-8 text-center text-gray-500">Veuillez vous connecter.</div>;

  return (
    <div className="w-full px-6 py-8">
      <div className="flex items-center justify-between mb-8">
        <div><h1 className="text-3xl font-bold text-white">Compte & <span className="gradient-text">Plan</span></h1></div>
        <button onClick={onLogout} className="flex items-center gap-2 px-4 py-2.5 rounded-xl border border-red-500/20 bg-red-500/10 text-red-400 text-sm hover:bg-red-500/20 transition-colors"><LogOut size={16} /> Deconnexion</button>
      </div>

      {/* Tabs */}
      <div className="flex gap-2 mb-8 border-b border-white/[0.06] pb-4">
        {[{ id: 'profile', label: 'Profil', icon: UserIcon }, { id: 'subscription', label: 'Abonnement', icon: Sparkles }, { id: 'billing', label: 'Facturation', icon: CreditCard }].map(tab => (
          <button key={tab.id} onClick={() => setActiveTab(tab.id as any)} className={`flex items-center gap-2 px-4 py-2 rounded-xl text-sm font-medium transition-all ${activeTab === tab.id ? 'bg-amber-500/10 border border-amber-500/30 text-amber-300' : 'text-gray-400 hover:text-white'}`}><tab.icon size={16} />{tab.label}</button>
        ))}
      </div>

      {/* Profile Tab */}
      {activeTab === 'profile' && (
        <div className="space-y-6 max-w-2xl">
          <div className="ninja-card p-6">
            <h3 className="text-lg font-bold text-white mb-4">Informations personnelles</h3>
            <div className="space-y-4">
              <div><label className="block text-sm font-medium text-gray-400 mb-1">Nom</label><div className="px-4 py-3 rounded-xl bg-white/[0.04] border border-white/[0.06] text-white">{user.name}</div></div>
              <div><label className="block text-sm font-medium text-gray-400 mb-1">Email</label><div className="px-4 py-3 rounded-xl bg-white/[0.04] border border-white/[0.06] text-white">{user.email}</div></div>
              <div><label className="block text-sm font-medium text-gray-400 mb-1">Plan</label><div className="px-4 py-3 rounded-xl bg-white/[0.04] border border-white/[0.06] text-amber-400 font-bold capitalize">{user.plan}</div></div>
            </div>
          </div>
          <div className="ninja-card p-6">
            <h3 className="text-lg font-bold text-white mb-4">Cle API</h3>
            <div className="flex items-center gap-3">
              <code className="flex-1 px-4 py-3 rounded-xl bg-white/[0.04] border border-white/[0.06] text-gray-400 font-mono text-sm">cb_pub_live_{(user.id || 'demo').substring(0, 16)}...</code>
              <button onClick={handleCopyApiKey} className="px-4 py-3 rounded-xl border border-white/[0.08] bg-white/[0.04] hover:bg-white/[0.08] text-gray-300 transition-colors">{apiKeyCopied ? <Check size={16} className="text-emerald-400" /> : <Copy size={16} />}</button>
            </div>
          </div>
        </div>
      )}

      {/* Subscription Tab */}
      {activeTab === 'subscription' && (
        <div>
          <div className="grid md:grid-cols-3 gap-6">
            {plans.map(plan => (
              <div key={plan.id} className={`ninja-card p-6 flex flex-col ${plan.popular ? '!border-amber-500/30 shadow-[0_0_40px_rgba(218,165,32,0.06)] md:scale-105 z-10' : ''} ${plan.current ? 'ring-2 ring-amber-500/30' : ''}`}>
                {plan.popular && <div className="text-xs font-bold text-amber-400 uppercase tracking-wider mb-3">Recommande</div>}
                <h3 className="text-xl font-bold text-white mb-1">{plan.name}</h3>
                <div className="flex items-baseline gap-1 mb-4"><span className="text-3xl font-bold text-white">{plan.price}€</span><span className="text-sm text-gray-600">/mois</span></div>
                <ul className="space-y-2 mb-6 flex-1">{plan.features.map((f, i) => <li key={i} className="flex items-start gap-2 text-sm text-gray-400"><Check size={14} className="text-amber-400 mt-0.5 shrink-0" />{f}</li>)}</ul>
                {plan.current ? (
                  <div className="w-full py-3 rounded-full text-center text-sm font-bold text-amber-400 border border-amber-500/30 bg-amber-500/10">Plan actuel</div>
                ) : (
                  <button onClick={() => { setUpgradeModal({ planId: plan.id, planName: plan.name, newPrice: plan.price }); setPaymentStep('recap'); }} className={`w-full py-3 rounded-full font-bold text-sm ${plan.popular ? 'btn-gradient' : 'bg-white/[0.04] border border-white/[0.08] text-gray-300 hover:bg-white/[0.07]'}`}>Passer a {plan.name}</button>
                )}
              </div>
            ))}
          </div>

          {/* Upgrade Modal */}
          {upgradeModal && (
            <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-black/80 backdrop-blur-sm" onClick={() => setUpgradeModal(null)}>
              <div className="relative w-full max-w-md bg-[#111111] border border-white/[0.08] rounded-2xl shadow-2xl p-6" onClick={e => e.stopPropagation()}>
                {paymentStep === 'recap' && (
                  <div><h3 className="text-xl font-bold text-white mb-4">Passer au plan {upgradeModal.planName}</h3><div className="ninja-card p-4 mb-6"><div className="flex justify-between"><span className="text-gray-400">Nouveau plan</span><span className="text-white font-bold">{upgradeModal.planName}</span></div><div className="flex justify-between mt-2"><span className="text-gray-400">Prix mensuel</span><span className="text-amber-400 font-bold">{upgradeModal.newPrice}€/mois</span></div></div><button onClick={() => setPaymentStep('payment')} className="btn-gradient w-full py-3 font-bold">Continuer vers le paiement</button></div>
                )}
                {paymentStep === 'payment' && (
                  <div><h3 className="text-xl font-bold text-white mb-4">Paiement</h3><StripeCheckout amount={upgradeModal.newPrice} onComplete={handleUpgradePayment} isProcessing={isProcessing} label={`Payer ${upgradeModal.newPrice}€/mois`} /><button onClick={() => setPaymentStep('recap')} className="w-full mt-4 text-center text-gray-500 text-sm hover:text-white">Retour</button></div>
                )}
                {paymentStep === 'success' && (
                  <div className="text-center py-6"><div className="text-4xl mb-4">&#9989;</div><h3 className="text-xl font-bold text-white mb-2">Bienvenue sur {upgradeModal.planName} !</h3><p className="text-gray-400 text-sm mb-6">Votre plan a ete mis a jour avec succes.</p><button onClick={() => setUpgradeModal(null)} className="btn-gradient px-8 py-3 font-bold">Fermer</button></div>
                )}
              </div>
            </div>
          )}
        </div>
      )}

      {/* Billing Tab */}
      {activeTab === 'billing' && (
        <div className="max-w-3xl">
          <div className="ninja-card p-6">
            <h3 className="text-lg font-bold text-white mb-4">Historique de facturation</h3>
            <div className="overflow-x-auto">
              <table className="w-full text-left text-sm">
                <thead><tr className="text-gray-500 border-b border-white/[0.06]"><th className="pb-3 font-medium">Reference</th><th className="pb-3 font-medium">Date</th><th className="pb-3 font-medium">Description</th><th className="pb-3 font-medium">Montant</th><th className="pb-3 font-medium">Statut</th></tr></thead>
                <tbody>
                  {paymentHistory.map(p => (
                    <tr key={p.id} className="border-b border-white/[0.06] last:border-0">
                      <td className="py-3 text-gray-300 font-mono text-xs">{p.id}</td>
                      <td className="py-3 text-gray-400">{p.date}</td>
                      <td className="py-3 text-gray-300">{p.desc}</td>
                      <td className="py-3 text-white font-bold">{p.amount.toFixed(2)}€</td>
                      <td className="py-3"><span className="px-2 py-0.5 rounded-full text-xs font-bold bg-emerald-500/15 text-emerald-400">{p.status}</span></td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default Account;
```

## FILE 3: C:\Users\User\citedby-public\pages\Affiliation.tsx

Gold-themed affiliation page with 3 tabs. Simplified from PRO.

```tsx
import React, { useState } from 'react';
import { Share2, DollarSign, Users, TrendingUp, Copy, Check, CreditCard, ChevronRight, ArrowUpRight, Wallet, BarChart3 } from 'lucide-react';
import { User } from '../types';

interface AffiliationProps {
  onBack: () => void;
  user: User | null;
}

const AFFILIATE_STATS = { totalEarned: 1450.50, pendingCommission: 320.00, clicks: 1240, conversions: 18, conversionRate: 1.45, nextPayoutDate: '01/05/2024' };
const REFERRALS = [
  { id: 'REF-001', name: 'StartUp Alpha', plan: 'Agency', commission: 59.80, status: 'active', date: '12/03/2024' },
  { id: 'REF-002', name: 'Jean Michel SEO', plan: 'Pro', commission: 17.80, status: 'active', date: '15/03/2024' },
  { id: 'REF-003', name: 'E-com Growth', plan: 'Starter', commission: 0, status: 'trial', date: '02/04/2024' },
  { id: 'REF-004', name: 'Agency One', plan: 'Agency', commission: 59.80, status: 'active', date: '20/02/2024' },
];
const PAYOUTS = [
  { id: 'PAY-892', date: '01/04/2024', amount: 450.00, status: 'paid', method: 'PayPal' },
  { id: 'PAY-756', date: '01/03/2024', amount: 380.50, status: 'paid', method: 'PayPal' },
  { id: 'PAY-621', date: '01/02/2024', amount: 620.00, status: 'paid', method: 'Virement' },
