            <div className="ninja-card p-5"><div className="text-2xl font-bold gradient-text">{AFFILIATE_STATS.totalEarned.toFixed(2)}€</div><div className="text-sm text-gray-500 mt-1">Total gagne</div></div>
            <div className="ninja-card p-5"><div className="text-2xl font-bold text-amber-400">{AFFILIATE_STATS.pendingCommission.toFixed(2)}€</div><div className="text-sm text-gray-500 mt-1">En attente</div></div>
            <div className="ninja-card p-5"><div className="text-2xl font-bold text-white">{AFFILIATE_STATS.clicks}</div><div className="text-sm text-gray-500 mt-1">Clics</div></div>
            <div className="ninja-card p-5"><div className="text-2xl font-bold text-white">{AFFILIATE_STATS.conversions}</div><div className="text-sm text-gray-500 mt-1">Conversions ({AFFILIATE_STATS.conversionRate}%)</div></div>
          </div>
          <div className="ninja-card p-6">
            <h3 className="text-lg font-bold text-white mb-4">Comment ca marche</h3>
